export function parseFinalizeClearInstruction<
  TProgram extends string,
  TAccountMetas extends readonly AccountMeta[],
>(
  instruction: Instruction<TProgram> &
    InstructionWithAccounts<TAccountMetas> &
    InstructionWithData<ReadonlyUint8Array>,
): ParsedFinalizeClearInstruction<TProgram, TAccountMetas> {
  if (instruction.accounts.length < 8) {
    throw new SolanaError(
      SOLANA_ERROR__PROGRAM_CLIENTS__INSUFFICIENT_ACCOUNT_METAS,
      {
        actualAccountMetas: instruction.accounts.length,
        expectedAccountMetas: 8,
      },
    );
  }
  let accountIndex = 0;
  const getNextAccount = () => {
    const accountMeta = (instruction.accounts as TAccountMetas)[accountIndex]!;
    accountIndex += 1;
    return accountMeta;
  };
  let optionalAccountsRemaining = instruction.accounts.length - 8;
  const getNextOptionalAccount = () => {
    if (optionalAccountsRemaining === 0) return undefined;
    optionalAccountsRemaining -= 1;
    return getNextAccount();
  };
  return {
    programAddress: instruction.programAddress,
    accounts: {
      cranker: getNextAccount(),
      market: getNextAccount(),
      histogram: getNextAccount(),
      orderSlab: getNextAccount(),
      clearingResult: getNextAccount(),
      systemProgram: getNextAccount(),
      eventAuthority: getNextAccount(),
      tempoProgram: getNextAccount(),
      crankerCollateral: getNextOptionalAccount(),
      vault: getNextOptionalAccount(),
    },
    data: getFinalizeClearInstructionDataDecoder().decode(instruction.data),
  };
}
